---@class LBattleDataMgr
local LBattleDataMgr = classX("LBattleDataMgr", nil)

local LBattleSkillData = require("LApp.gameplay.videobattle.data.LBattleSkillData")

function LBattleDataMgr:ctor()
    self._reportMap = {}
    self._skillShowMap = {}

    self._skillExpressionList = {}
    self._skinToExpressList = {}
    self._skillEffList = {}
    self._monsterSkinRecord = {}

    self._freezeStates = {
        [LBuffStateConst.BUFF_STATE_FROZEN] = true,
        [LBuffStateConst.BUFF_STATE_SLEEP] = true,
        [LBuffStateConst.BUFF_STATE_DIZZY] = true,
        [LBuffStateConst.BUFF_STATE_PALSY] = true,
    }
end

function LBattleDataMgr:Dispose()
    for i, v in pairs(self._skillShowMap) do
        v:Dispose()
    end

    self._skillShowMap = {}
end

function LBattleDataMgr:Initialize()
    self:CreateGeneralSkill()
end


---@param skillShowName string 技能显示ID
---@param onGetCallback function 要加载资源，所以下一步逻辑在callback处理
function LBattleDataMgr:GetSkillShow(skillShowName, onGetCallback, bForce)
    if not self._skillShowMap or string.isempty(skillShowName) then
        if onGetCallback then
            onGetCallback()
        end
        return
    end
    ---@type LBattleShowSkillData
    local showSkillData = self._skillShowMap[skillShowName]
    if not showSkillData then
        showSkillData = require("LApp.gameplay.videobattle.data.LBattleShowSkillData"):new()
        self._skillShowMap[skillShowName] = showSkillData
    end
    showSkillData:LoadSkillData(skillShowName, onGetCallback, bForce)
    return showSkillData
end

function LBattleDataMgr:GetSkillShowByEditor(skillShowName)
    if not self._skillShowMap or string.isempty(skillShowName) then return end
    ---@type LBattleShowSkillData
    local showSkillData = self._skillShowMap[skillShowName]
    if not showSkillData then
        showSkillData = require("LApp.gameplay.videobattle.data.LBattleShowSkillData"):new()
        self._skillShowMap[skillShowName] = showSkillData
    end
    return showSkillData
end


---@param skillShowName string 技能显示ID
function LBattleDataMgr:RemoveSkillShow(skillShowName)
    ---@type LBattleShowSkillData
    local showSkillData = self._skillShowMap[skillShowName]
    if showSkillData then
        showSkillData:Dispose()
    end
    self._skillShowMap[skillShowName] = nil
end
--- 获得一个战报
---@param reportId string 战报ID
function LBattleDataMgr:GetReport(reportId)
    ---@type LFightReportData
    local reportData = self._reportMap[reportId]
    if not reportData then
        reportData = require("LApp.gameplay.videobattle.data.LFightReportData"):new(reportId)
        self._reportMap[reportId] = reportData
    end
