--- 新建一个战报，不管以前有没有
---@param reportId string 战报ID
function LBattleDataMgr:NewReport(reportId)
    ---@type LFightReportData
    local battleReport = self._battleReports[reportId]
    if battleReport ~= nil then
        battleReport:Dispose()
    end
    local reportData = require("LApp.gameplay.videobattle.data.LFightReportData"):new(reportId)
    self._reportMap[reportId] = reportData
    return reportData
end


