--- 判断buff是否是溅射
function LBattleDataMgr:CheckBuffHasJianShe(buffId)
    local effIdList = self:GetBuffEffectIDByBuffID(buffId)
    if not effIdList then
        return false
    end
    for k, v in ipairs(effIdList) do
        local data = GameTable.CombatBuffEffectRef[v]
        if data and data.effectId == LBuffStateConst.BUFF_STATE_JIANSHE then
            return true, data
        end
    end
    return false
end

function LBattleDataMgr:GetQulingId(buffId)
    local effIdList = self:GetBuffEffectIDByBuffID(buffId)
    if not effIdList then
        return
    end
    for k, v in ipairs(effIdList) do
        local data = GameTable.CombatBuffEffectRef[v]
        if data and data.effectId == LBuffStateConst.BUFF_STATE_SHENGLING then
            local qulingId = tonumber(data.effectValue3)
            return qulingId
        end
    end
end

function LBattleDataMgr:GetBuffBuffUi(refId)
    local buffRef = GameTable.CombatBuffRef[refId]
    local buffUIStr = buffRef and buffRef.buffUi or ""
    if string.isempty(buffUIStr) then
        return
    end

    local strs = string.split(buffUIStr,"=")
    local type = tonumber(strs[1])
    local temps = string.split(strs[2],":")
    local para =
    {
        uiType= type,
        baPath = temps[1],
        bgPath1 = string.format("%s_1",temps[1]),
        fillPath = temps[2],
        fillPath1 = temps[3],
    }

    return para
end

function LBattleDataMgr:IsFreezeBuff(id)
    local stateList = self:GetBuffStateIDByBuffID(id)
    if not stateList then
        return false
    end
    for k, v in ipairs(stateList) do
        if self._freezeStates[v] then
            return true
        end
    end
    return false
end

-- 获取英雄小人特效, nil 表示没有
function LBattleDataMgr:GetHeroXREffect(heroRefId, star)
    local needStar = GameTable.CharacterConfigRef["highHeroXREffect"]
    if star < needStar then
        return nil
    end

    local heroRef = GameTable.heroRef[heroRefId]
    if not heroRef then
        return nil
    end

    local heroRaceRef = GameTable.CharacterRaceRef[heroRef.raceType]
    if heroRef.superHero == 0 then
        return heroRaceRef.xrEffect1
    end

    return heroRaceRef.xrEffect2
end

function LBattleDataMgr:GetBuffEffectIDByBuffID(id)
    local data = GameTable.CombatBuffRef[id]
    if not data then
        return nil
    end

    local effectList = {}
    local effectId = data.effectId
    if not string.isempty(effectId) then
        local tempList = string.split(effectId, "|")
        for k, v in ipairs(tempList) do
            local id = tonumber(v)
            table.insert(effectList, id)
        end
        return effectList
    else
        return nil
    end
end

---技能表现数据获取
function LBattleDataMgr:GetSkillExpressionId(skillExpressId,attackCnt)
    local expression = self:GetExpressConfigData(skillExpressId)
    if not expression then
        --printInfoN(string.format("expression is nil id %s cnt %s",skillExpressId,attackCnt))
        return
    end

    if expression.type == 1 then
        return skillExpressId
    elseif expression.type == 2 then
        local numList = expression.numList
        local first = numList[1]
        local last = numList[#numList]

        local key =Mathf.Clamp(attackCnt,first,last)
        local expressionId = expression.effectList[key]

        return expressionId
    end
end

function LBattleDataMgr:GetExpressConfigData(expressId)
    local cfg = GameTable.SnakeSkillExpressionRef[expressId]
    if not cfg then
        return
    end
    local expressData = self._skillExpressionList[expressId]
    if not expressData then
        expressData = self:ParseSingleExpress(cfg)
    end

    return expressData
end

---@param skillExpressCfg V_SkillExpressionRef
function LBattleDataMgr:ParseSingleExpress(skillExpressCfg)
    local data = nil
    local playEffType = skillExpressCfg.playEffType
    local playEff = skillExpressCfg.playEff

    local hitEffList = {}
    --- 1：溅射受击（填写技能动效表对应ID）
    ----# 1=溅射弹道ID=溅射受击特效ID
    ----# 溅射弹道：填写特效名，无则填0
    ----# 受击特效：填写特效名，无则填0
    ----# 该项默认不填，则无溅射受击特殊表现效果
    local hitEffType = skillExpressCfg.hitEffType
    if not string.isempty(hitEffType) then
        hitEffType = string.split(hitEffType,"=")
        table.insert(hitEffList,{
            hitEffectType = tonumber(hitEffType[1]),
            hitBullet = tonumber(hitEffType[2]),
            hitEffRefId = tonumber(hitEffType[3]),
        })
    end

    local effectList = LxDataHelper.ParseNumber_Sign(playEff)
    if string.isempty(playEffType) then
        data = {type = 1,effectList = effectList,hitEffList = hitEffList}
    else
        local effType = self:ParsePlayEffType(playEffType)
        if effType then
            if effType.type == 1 then
                local cnt = #effType.numList
                local temp = {}
                for k1 = 1,cnt do
                    local key = effType.numList[k1]
                    local value = effectList[k1]
                    temp[key] = value
                end
                data = {type = 2,effectList = temp,numList = effType.numList,hitEffList = hitEffList}
            end
        end
    end

    return data
end

function LBattleDataMgr:ParsePlayEffType(str)
    local strs = string.split(str,"=")
    if #strs>=2 then
        local type  = tonumber(strs[1])
        local numList = LxDataHelper.ParseNumber_Sign(strs[2])
        return {type = type,numList = numList}
    end
end

function LBattleDataMgr:GetTreasureSkinExpress(skinId,defaultExpress)
    --local cfg = GameTable.SkillSkinRelationTreasureRef[defaultExpress]
    local cfg = nil
    if not cfg then
        return defaultExpress
    end

    if not self._treaSkinToExpressList then
        self._treaSkinToExpressList = {}
    end

    local skinToExpress = self._treaSkinToExpressList[defaultExpress]
    if not skinToExpress then
        local skinSkillExpression = cfg.skinSkillExpression
        skinToExpress = self:ParseSingleSkin(skinSkillExpression)
        self._treaSkinToExpressList[defaultExpress] = skinToExpress
    end

    local express = skinToExpress[skinId]
    if express then
        if LOG_INFO_ENABLED then
            printInfo("battle", string.format("treasure use skinid %s expressid %s",tostring(skinId),tostring(express)))
        end
        return express
    end
    if LOG_INFO_ENABLED then
        printInfo("battle", string.format("treasure use defalut skinid %s expressid %s",tostring(skinId),tostring(defaultExpress)))
    end
    return defaultExpress
end

function LBattleDataMgr:ParseSingleSkin(skinSkillExpression)
    local strs = string.split(skinSkillExpression,",")
    local skinToExpress ={}
    for k1,v1 in ipairs(strs) do
        local tempStrs = string.split(v1,"=")
        if #tempStrs>=2 then
            local skinId = tonumber(tempStrs[1])
            local express = tonumber(tempStrs[2])
            skinToExpress[skinId] = express
        end
    end
    return skinToExpress
end

function LBattleDataMgr:GetSkinExpress(skinId,defaultExpress,useRef)
    -- SkillSkinRelationRef 配置已删
    if not useRef then
        return defaultExpress
    end

    local cfg = GameTable.SnakeSkillSkinRelationRef[defaultExpress]
    if not cfg then
        return defaultExpress
    end

    local skinToExpress = self._skinToExpressList[defaultExpress]
    if not skinToExpress then
        local skinSkillExpression = cfg.skinSkillExpression
        skinToExpress = self:ParseSingleSkin(skinSkillExpression)
        self._skinToExpressList[defaultExpress] = skinToExpress
    end

    local express = skinToExpress[skinId]
    if express then
        return express
    end
    return defaultExpress
end

function LBattleDataMgr:GetSkinSkillType(skinId,expressionId)
    local cfg = GameTable.SnakeSkillSkinRelationRef[expressionId]
    if not cfg then
        return LFightConst.SKIN_SKILLTYPE_NORMAL
    end
    if not self._skinToSkillType then
        self._skinToSkillType = {}
    end
    local skinToSkillType = self._skinToSkillType[expressionId]
    if not skinToSkillType then
        skinToSkillType = {}

        local skillType = cfg.skillType
        local skinSkillExpression = cfg.skinSkillExpression
        local skinToExpress = self:ParseSingleSkin(skinSkillExpression)
        for _skinId,express in pairs(skinToExpress) do
            skinToSkillType[_skinId] = skillType
        end
        self._skinToSkillType[expressionId] = skinToSkillType
    end
    local data = skinToSkillType[skinId]
    if data then return data end

    return LFightConst.SKIN_SKILLTYPE_NORMAL
end

function LBattleDataMgr:GetGeneralSkillData(expressionId)
    return self._skillDataList[expressionId]
end

function LBattleDataMgr:CreateGeneralSkill()

    local skillDataList = {}

    local para = GameTable.CharacterConfigRef["heroBelongSkillGroup"] or ""
    local strs = string.split(para,",")
    for k,v in ipairs(strs) do
        local tempstrs = string.split(v,"=")
        if #tempstrs>=2 then
            local type = tonumber(tempstrs[1])
            local isNormal = type == 1
            local skillId = tonumber(tempstrs[2])
            local skillExpressList = self:GetExpressionList(skillId)
            for k1,v1 in ipairs(skillExpressList) do
                local expressionList = self:GetSkillPlayEffList(v1.expressionId)
                if expressionList then
                    for k2,v2 in ipairs(expressionList) do
                        local expressId = v2
                        local skillData = LBattleSkillData:new(self)
                        if skillData:InitData(skillId,v1.skillEffId,expressId,isNormal) then
                            skillDataList[expressId] = skillData
                        end
                    end
                end
            end

        end
    end

    self._skillDataList = skillDataList
end

function LBattleDataMgr:GetSkillDataCommon(skillId,expressId,skinId,skillType)
    if LOG_INFO_ENABLED then
        printInfo("battle", string.format("战斗中没找到skillData skillId %s ,expressId %s, 从皮肤技能中查找",tostring(skillId),tostring(expressId)))
    end

    local skillDataList = self._skillDataList or {}
    local skillData = skillDataList[expressId]
    if skillData then
        return skillData
    end

    self._skillDataList = skillDataList


    local skillExpressList = self:GetExpressionList(skillId)
    for k1,v1 in ipairs(skillExpressList) do
        local expressionList = self:GetSkillPlayEffList(v1.expressionId)
        if expressionList then
            for k2,v2 in ipairs(expressionList) do
                local tempRefId = v2
                local skinTempRefId = self:GetSkinExpress(skinId,tempRefId,true)

                local lSkillData = LBattleSkillData:new(self)
                lSkillData:SetSkinSkillType(skillType)
                if lSkillData:InitData(skillId,v1.skillEffId,skinTempRefId,false,skinId) then
                    skillDataList[skinTempRefId] = lSkillData
                end
            end
        end
    end

    return skillDataList[expressId]

end

function LBattleDataMgr:GetSkillPlayEffList(skillExpressId)
    local expression = self:GetExpressConfigData(skillExpressId)
    if not expression then
        printError("battle", string.format("expression is nil id %s",tostring(skillExpressId)))
        return
    end

    if expression.type == 1 then
        return {skillExpressId}
    else
        local list = {}
        for k,v in pairs(expression.effectList) do
            table.insert(list,v)
        end
        return list
    end

end

function LBattleDataMgr:GetParsePlayNumFunc(effType)
    if not self._playNumParse then
        self._playNumParse =
        {
            [LSkillEffConst.PLAY_EFF_BULLET] = function(value) return self:ParsePlayNumOne(value) end,
            [LSkillEffConst.PLAY_EFF_HIT_HUD] = function(value) return self:ParsePlayNumTwo(value) end,
        }
    end

    local func = self._playNumParse[effType]
    if not func then
        func = function(value) return tonumber(value) end
    end
    return func
end

function LBattleDataMgr:ParsePlayNumOne(value)
    local playNumTable = {}
    local strList = string.split(value,",") or {}
    for e, q in ipairs(strList) do
        table.insert(playNumTable,tonumber(q) or 0)
    end
    return playNumTable
end

function LBattleDataMgr:ParsePlayNumTwo(value)
    local playNumTable = {}
    local strList = string.split(value,",") or {}
    for i, v in ipairs(strList) do
        local stringList = string.split(v,"=") or {}
        local number = {}
        for j, k in ipairs(stringList) do
            table.insert(number,tonumber(k) or 0)
        end
        if #number >= 2 then
            table.insert(playNumTable,number)
        end
    end

    return playNumTable
end
--返回技能效果列表
function LBattleDataMgr:GetEffectList(skillId)
    local skillCfg = GameTable.SnakeSkillRef[skillId]
    if not skillCfg then
        return {}
    end

    local effList = self._skillEffList[skillId]
    if not effList then
        effList = self:ParseSingleSkillEff(skillCfg.skillEffect)
        self._skillEffList[skillId] = effList
    end

    return effList
end
function LBattleDataMgr:GetExpressionList(skillId)
    local skillCfg = GameTable.SnakeSkillRef[skillId]
    if not skillCfg then
        return {}
    end

    local effList = self._skillEffList[skillId]
    if not effList then
        effList = self:ParseSingleSkillEff(skillCfg.skillEffect)
        self._skillEffList[skillId] = effList
    end

    local dataList = {}
    if effList then
        for k,v in ipairs(effList) do
            local cfg = GameTable.SnakeSkillEffectRef[v]
            if cfg then
                local expressionId = cfg.skillShowEff
                if expressionId > 0 then
                    local data = {
                        skillEffId = v,
                        expressionId = expressionId,
                    }
                    table.insert(dataList,data)
                end
            end
        end
    end

    return dataList
end

function LBattleDataMgr:ParseSingleSkillEff(skillEffect)
    local idList = {}
    local moreSplitList = string.split(skillEffect,";")
    if moreSplitList and #moreSplitList > 1 then
        for i,v in ipairs(moreSplitList) do
            self:_ParseSingleSkillEff(v,idList)
        end
    else
        self:_ParseSingleSkillEff(skillEffect,idList)
    end

    return idList
end

function LBattleDataMgr:_ParseSingleSkillEff(effectStr,idList)
    local ids = {}
    local needSplit = string.split(effectStr,"=")
    if needSplit and #needSplit > 2 then
        local type = tonumber(needSplit[1])
        local str = needSplit[3]
        str = string.gsub(str, "{", "")
        str = string.gsub(str, "}", "")
        if type ==1 or type == 2 or type == 3 then
            ids = LxDataHelper.ParseNumber_Sign(str,",")
        elseif type == 4 then
            str = string.split(str,",")
            for k,v in ipairs(str) do
                local tempList = LxDataHelper.ParseNumber_Sign(v)
                for k1,v1 in ipairs(tempList) do
                    table.insert(ids,v1)
                end
            end
        end
    else
        ids = LxDataHelper.ParseNumber_Sign(effectStr)
    end
    for i,v in ipairs(ids) do
        table.insert(idList,tonumber(v))
    end
end

function LBattleDataMgr:IsSameSkillGroup(skillExpressList)
    if not skillExpressList or #skillExpressList < 1 then return false end

    local sameNum = 0
    local recordGroup
    local skillEffGroup
    local skillEffecrRef
    for i,v in ipairs(skillExpressList) do
        skillEffecrRef = GameTable.SnakeSkillEffectRef[tonumber(v.skillEffId)]
        if skillEffecrRef then
            skillEffGroup = skillEffecrRef.skillEffGroup
            if skillEffGroup and skillEffGroup > 0 then
                if not recordGroup then
                    recordGroup = skillEffGroup
                    sameNum = sameNum + 1
                elseif recordGroup == skillEffGroup then
                    sameNum = sameNum + 1
                end
            end
        end
    end
    return sameNum == #skillExpressList
end

function LBattleDataMgr:GetSingleSkillData(skillId,expressId,skinId,expressionRefId)
    local skillDataList = self._skillDataList or {}
    local skillData = skillDataList[expressId]
    if skillData then
        return skillData
    end

    self._skillDataList = skillDataList

    local skillExpressList = self:GetExpressionList(skillId)
    for k1,v1 in ipairs(skillExpressList) do
        local lSkillData = LBattleSkillData:new(self)
        if lSkillData:InitData(skillId,v1.skillEffId,expressId,false,skinId) then
            skillDataList[expressId] = lSkillData
        end
    end

    return skillDataList[expressId]
end

function LBattleDataMgr:GetReliveSkillType(skillId)
    if (skillId==0) then
        return 0
    end
    local ref = GameTable.SnakeSkillRef[skillId]
    if not ref then
        return 0
    end

    return ref.revive
end

function LBattleDataMgr:GetSkillCdRound(refId)
    local cfg = GameTable.SnakeSkillRef[refId]
    if not cfg then
        return 0
    end
    return cfg.cdRound
end

function LBattleDataMgr:GetSummonShowSkin(monsterRefId,skinId)
    local record = self._monsterSkinRecord[monsterRefId]
    if record then
        return record[skinId]
    end

    local ref = GameTable.SnakeSkillMonsterSkinRef[monsterRefId]
    if not ref then
        return
    end
    local skinMonster = ref.skinMonster
    local strs = string.split(skinMonster,',')
    record = {}
    for k,v in ipairs(strs) do
        local temps = string.split(v,'=')
        record[tonumber(temps[1])] = tonumber(temps[2])
    end
    self._monsterSkinRecord[monsterRefId] = record
    return record[skinId]
end

function LBattleDataMgr:GetTotalDelay(playNum)
    local totalDelay = 0
    if playNum and #playNum>0 then
        local last = playNum[#playNum]
        totalDelay = last[1]
    end

    return totalDelay
end

function LBattleDataMgr:IsShowAfterDead(buffId)
    local cfg = GameTable.CombatBuffRef[buffId]
    if cfg then
        local showTime = cfg.buffEffShowTime
        return showTime == 1
    end
    return false
end

function LBattleDataMgr:ParamsSkillBuffEffDamageTypes(refId)
    if not self._buffEffDamageTypes then
        self._buffEffDamageTypes = {}
    end
    local damageTypeMap = self._buffEffDamageTypes[refId]
    if not damageTypeMap then
        ---@type V_BuffRef
        local ref = GameTable.CombatBuffRef[refId]
        if ref and not string.isempty(ref.buffEffDamageType) then
            local buffEffDamageType = string.split(ref.buffEffDamageType,"|")
            damageTypeMap = {}
            for i,v in ipairs(buffEffDamageType) do
                v = tonumber(v)
                damageTypeMap[v] = true
            end
            self._buffEffDamageTypes[refId] = damageTypeMap
        end
    end
    return damageTypeMap
end

function LBattleDataMgr:CheckNeedShowDamageBuffEff(buffId,ht)
    local damageTypeMap = self:ParamsSkillBuffEffDamageTypes(buffId)
    if not damageTypeMap then return false end
    return damageTypeMap[ht]
end

function LBattleDataMgr:GetBuffEffShowPosById(id)
    local buffRefData = GameTable.CombatBuffRef[id]
    if buffRefData then
        return buffRefData.buffEffShowPos
    end
    return 1
end

function LBattleDataMgr:GetBuffSkillData(refId,skinId)
    local ref = GameTable.CombatBuffRef[refId]
    if not ref then
        if LOG_INFO_ENABLED then
            printError("battle", string.format("no buff ref id %s",tostring(refId)))
        end
        return
    end

    if string.isempty(ref.buffSkill) then
        return
    end

    local strs = string.split(ref.buffSkill,"=")
    local expressionId = tonumber(strs[1])
    local showState = tonumber(strs[2]) --1 死亡状态不表现，2 死亡状态表现
    expressionId = self:GetSkinExpress(skinId,expressionId)
    return expressionId,showState
end

function LBattleDataMgr:GetBuffStateIDByBuffID(id)
    if not id then
        return
    end

    local buffStateIDList = {}
    local effectIdList = self:GetBuffEffectIDByBuffID(id)
    for i, v in ipairs(effectIdList) do
        local data = GameTable.CombatBuffEffectRef[v]
        if data and data.effectType == 2 then
            -- 类型2：影响英雄的2级状态
            table.insert(buffStateIDList, data.effectId)
        end
    end

    return buffStateIDList
end

--- 是否 92 类型
function LBattleDataMgr:CheckBuffEffectIs92(effectId)
    local effectRef = GameTable.CombatBuffEffectRef[effectId]
    if not effectRef then
        return false
    end
    return effectRef.effectId == 92
end

-- 通过技能id获取龙语配置
function LBattleDataMgr:GetDraconicRefBySkillId(skillId)
    if not self._skillDraconicRefMap then
        self._skillDraconicRefMap = {}
        local DraconicRef = GameTable.DraconicRef
        for k, v in pairs(GameTable.DraconicSuitRankRef) do
            self._skillDraconicRefMap[v.skillId] = { ref = DraconicRef[v.type], upRef = v }
        end
    end

    local data = self._skillDraconicRefMap[skillId]
    if data then
        return data.ref, data.upRef
    end
    return nil, nil
end

function LBattleDataMgr:IsMultiBulletShow(refId,vfxId)
    local cfg = GameTable.SnakeSkillEffectRef[refId]
    if not cfg then
        --printInfoN("skillEffectRef is nil refId "..(refId or ""))
        return false
    end
    local isTrue = cfg.skillShowType == 1
    if not isTrue then
        return false
    end

    local index = self:GetMultiBulletIndex(vfxId)

    return true,index
end

function LBattleDataMgr:GetMultiBulletIndex(expressionId)
    local cfg = GameTable.SnakeSkillVfxRef[expressionId]
    if not cfg then
        return 1
    end
    local effType = cfg.effType
    if effType == LSkillEffConst.PLAY_EFF_HIT_HUD or effType == LSkillEffConst.PLAY_EFF_HUD then
        return effType.effTargetIndex
    end
    local nextPlay = cfg.nextPlay
    local nextPlayIds = LxDataHelper.ParseNumber_Sign(nextPlay,"|")
    for k,v in ipairs(nextPlayIds) do
        local temp = GameTable.SnakeSkillVfxRef[v]
        effType = temp.effType
        if effType == LSkillEffConst.PLAY_EFF_HIT_HUD or effType == LSkillEffConst.PLAY_EFF_HUD then
            return temp.effTargetIndex
        end
    end

    return 1
end

function LBattleDataMgr:FormatBloodPlayData(oldHp,newHp,time,playNum)
    local change = newHp - oldHp
    local dataList = {}
    local sTime = time
    local changePercent = 0
    local data =nil
    local tempTime = sTime
    if playNum and #playNum>0 then
        for i, v in ipairs(playNum) do
            changePercent = changePercent + v[2]
            data =
            {
                startTime = tempTime,
                curHp = oldHp + math.floor(changePercent* change),
            }
            tempTime = sTime + v[1]
            table.insert(dataList,data)
        end
    end

    data =
    {
        startTime = tempTime,
        curHp = newHp,
    }

    table.insert(dataList,data)
    return dataList
end

function LBattleDataMgr:GetBuffEffShowTypeById(id)
    local buffRefData = GameTable.CombatBuffRef[id]
    if buffRefData then
        return buffRefData.buffEffShowType
    end
    return -1
end

function LBattleDataMgr:GetBuffAct(refId)
    local bufRef = GameTable.CombatBuffRef[refId]
    if not bufRef then
        return
    end
    local act = bufRef.buffAct

    if string.isempty(act) then
        return
    end

    local strs = string.split(act,"=")
    local spineName = strs[1]
    local temps = string.split(strs[2],';')
    local aniList = {}
    for k,v in ipairs(temps) do
        local temp = string.split(v,":")
        local cnt = tonumber(temp[1])
        local ani = temp[2]
        table.insert(aniList,{cnt = cnt,ani = ani})
    end
    return {spineName = spineName,aniList = aniList}
end
