---@region 英雄数据
function LBattleDataMgr:GetHeroOriginId(refId)
    --Hero:GetOriginId(refId)
    if not self._originId then
        self:InitHeroOriginEffectRef()
    end
    return self._originId[refId]
end

function LBattleDataMgr:InitHeroOriginEffectRef()
    local HeroEffectRefList = self._HeroEffectRefList
    if not HeroEffectRefList then
        HeroEffectRefList = {}
        self._HeroEffectRefList = HeroEffectRefList
    end

    --处理多形态的数据  数据格式为 [originID]={id} sord by needStar
    local polymorphism = {}
    local originId = {}
    local originRefId, needStar
    for k, v in pairs(GameTable.CharacterEffectRef) do
        local jumpItem = v.jumpItem
        if not string.isempty(jumpItem) then
            local jumpItemList = string.split(jumpItem, "|")
            for idx, itemRefId in ipairs(jumpItemList) do
                local itemData = HeroEffectRefList[k]
                if not itemData then
                    itemData = {}
                    HeroEffectRefList[k] = itemData
                end
                local toNum = tonumber(itemRefId)
                itemData[toNum] = toNum
            end
        end

        originRefId = v.originRefId
        needStar = v.needStar
        if originRefId and originRefId > 0 and needStar and needStar > 0 then
            local data = { refId = k, needStar = needStar }
            local tmpList = polymorphism[originRefId]
            if not tmpList then
                tmpList = {}
                polymorphism[originRefId] = tmpList
            end
            table.insert(tmpList, data)

            originId[k] = originRefId
        end
    end

    for k, v in pairs(polymorphism) do
        table.sort(v, function(a, b)
            return a.needStar < b.needStar
        end)
    end
    self._polymorphism = polymorphism
    self._originId = originId
end

local SKILL_SOUND_1 = "skillSound1"
local SKILL_SOUND_2 = "skillSound2"

local RECORD_SKILLSOUND_MAP = {
    [SKILL_SOUND_1] = 1,
    [SKILL_SOUND_2] = 2,
}

function LBattleDataMgr:GetHeroFavorabilitySounds(loveLevel, effData)
    if not effData then
        return
    end

    local skinSkillType = effData.skinSkillType
    if not skinSkillType then
        return
    end

    local SpActionSound
    if not self._recordBattleSounds then
        self:InitHeroFavorabilityRef()
    end
    for i, v in ipairs(self._recordBattleSounds) do
        if loveLevel >= v.refId then
            SpActionSound = v.SpActionSound
            if RECORD_SKILLSOUND_MAP[SpActionSound] == skinSkillType then
                return SpActionSound
            end
        end
    end
end

function LBattleDataMgr:InitHeroFavorabilityRef()
    local recordBattleSounds = {}
    local SpActionSound
    if GameTable.CharacterFavorabilityRef then
        for k, v in pairs(GameTable.CharacterFavorabilityRef) do
            SpActionSound = v.SpActionSound
            if RECORD_SKILLSOUND_MAP[SpActionSound] then
                table.insert(recordBattleSounds, {
                    SpActionSound = SpActionSound,
                    refId = v.refId
                })
            end
        end
        table.sort(recordBattleSounds, function(a, b)
            return a.refId > b.refId
        end)
    end
    self._recordBattleSounds = recordBattleSounds
end

function LBattleDataMgr:GetHeroShowEffectRef(refId, star, skin, form)
    local effId = nil
    if skin and skin > 0 then
        effId = skin
    else
        effId = self:GetHeroEffectId(refId, form, star)
    end

    local effRef = GameTable.CharacterEffectRef[effId]
    if not effRef then
        if LOG_INFO_ENABLED then
            printError("battle", string.format("英雄表现表缺少配置 refId %s", tostring(effId)))
        end
    end
    return effRef
end

